{
  "mode": "method",
  "tests": [
    {
      "name": "schedule_one_time_task",
      "input": {
        "challengeId": "123",
        "phaseId": "456",
        "endTime": "2023-10-01T12:00:00Z"
      },
      "output": {
        "status": "success",
        "message": "Task scheduled successfully"
      },
      "args": [],
      "notes": "Validates that a one-time task can be scheduled correctly."
    },
    {
      "name": "trigger_phase_transition_event",
      "input": {
        "challengeId": "123",
        "phaseId": "456"
      },
      "output": {
        "status": "event_triggered",
        "event": {
          "challengeId": "123",
          "phaseId": "456",
          "timestamp": "2023-10-01T12:00:00Z"
        }
      },
      "args": [],
      "notes": "Checks if the phase transition event is triggered at the correct time."
    },
    {
      "name": "cancel_scheduled_task",
      "input": {
        "taskId": "789"
      },
      "output": {
        "status": "success",
        "message": "Task canceled successfully"
      },
      "args": [],
      "notes": "Ensures that a scheduled task can be canceled."
    },
    {
      "name": "schedule_task_invalid_time",
      "input": {
        "challengeId": "123",
        "phaseId": "456",
        "endTime": "2023-09-30T12:00:00Z"
      },
      "output": {
        "status": "error",
        "message": "End time must be in the future"
      },
      "args": [],
      "notes": "Tests edge case where the end time is in the past."
    },
    {
      "name": "publish_event_to_kafka",
      "input": {
        "challengeId": "123",
        "phaseId": "456"
      },
      "output": {
        "status": "published",
        "topic": "autopilot.phase.transition"
      },
      "args": [],
      "notes": "Validates that the event is published to the correct Kafka topic."
    },
    {
      "name": "schedule_multiple_tasks",
      "input": [
        {
          "challengeId": "123",
          "phaseId": "456",
          "endTime": "2023-10-01T12:00:00Z"
        },
        {
          "challengeId": "124",
          "phaseId": "457",
          "endTime": "2023-10-01T13:00:00Z"
        }
      ],
      "output": {
        "status": "success",
        "message": "Multiple tasks scheduled successfully"
      },
      "args": [],
      "notes": "Checks if multiple tasks can be scheduled at once."
    },
    {
      "name": "invalid_phase_id",
      "input": {
        "challengeId": "123",
        "phaseId": "invalid"
      },
      "output": {
        "status": "error",
        "message": "Invalid phase ID"
      },
      "args": [],
      "notes": "Tests edge case where the phase ID is invalid."
    },
    {
      "name": "check_scheduler_registry",
      "input": {},
      "output": {
        "scheduledTasks": [
          {
            "taskId": "789",
            "challengeId": "123",
            "phaseId": "456"
          }
        ]
      },
      "args": [],
      "notes": "Validates that the scheduler registry contains the expected tasks."
